import { describe, expect, it } from 'vitest';
import { estimateMeanInstFreqHz } from './fm-demod';
import { forkRaceFoldIfDemod } from './pipeline';
import {
  generateSyntheticCwSpinIqU8,
  generateSyntheticFmNwrLikeIqU8,
} from './synthetic';

describe('rtlsdr-mock-sim', () => {
  it('mean IQ phase-diff estimates CW spin (TS lab; not FM-accurate)', () => {
    const fs = 2_048_000;
    const spinHz = 5000;
    const iq = generateSyntheticCwSpinIqU8({
      sampleRateHz: fs,
      durationSec: 0.15,
      noiseRms: 0,
      spinHz,
    });
    const est = estimateMeanInstFreqHz(
      iq,
      fs,
      Math.min(200_000, Math.floor(iq.length / 2) - 1),
    );
    expect(Math.abs(est - spinHz)).toBeLessThan(80);
  });

  it('FM-like synthetic: mesh IF search yields finite audio (heuristic scorer)', () => {
    const iqRate = 2_048_000;
    const iq = generateSyntheticFmNwrLikeIqU8({
      sampleRateHz: iqRate,
      durationSec: 0.12,
      noiseRms: 0,
      ifErrorHz: 4500,
      fmDeviationHz: 7500,
      messageToneHz: 880,
    });
    const ifOffsetsHz = Array.from({ length: 49 }, (_, i) => -12_000 + i * 500);
    const fold = forkRaceFoldIfDemod(iq, {
      iqSampleRateHz: iqRate,
      audioSampleRateHz: 48_000,
      ifOffsetsHz,
      scoreMessageHz: 880,
    });
    expect(Number.isFinite(fold.bestScore)).toBe(true);
    expect(fold.pcm16.length).toBeGreaterThan(200);
  });
});
